using Microsoft.AspNetCore.Mvc;
using System.Collections.Generic;
using System.Linq;
using System.Web; // Required for HttpUtility

public class ProductController : Controller
{
    private readonly ApplicationDbContext _context; // Assuming you have a DbContext

    public ProductController(ApplicationDbContext context)
    {
        _context = context;
    }

    // GET: /Product/Details/{productId}
    public IActionResult Details(int productId)
    {
        // Fetch product details (optional, but good practice for a product page)
        var product = _context.Products.FirstOrDefault(p => p.Id == productId);
        if (product == null)
        {
            return NotFound();
        }

        // Fetch reviews for the specific product
        var reviews = _context.Reviews
                              .Where(r => r.ProductId == productId)
                              .OrderByDescending(r => r.ReviewDate)
                              .ToList();

        var model = new ProductDetailsViewModel
        {
            Product = product,
            Reviews = reviews
        };

        return View(model);
    }

    // This is a simplified example of the models you might use.
    // In a real application, these would likely be in separate files.

    public class ProductDetailsViewModel
    {
        public Product Product { get; set; }
        public List<Review> Reviews { get; set; }
    }

    public class Product
    {
        public int Id { get; set; }
        public string Name { get; set; }
        public string Description { get; set; }
        // ... other product properties
    }

    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        public string AuthorName { get; set; }
        public string ReviewText { get; set; }
        public int Rating { get; set; } // e.g., 1-5 stars
        public DateTime ReviewDate { get; set; }
    }
}

